mapper.select:
/* 장치그룹목록 조회 */
select 
	device_grp_idx, site_id, user_idx, device_grp_name, del_yn, reg_uid, reg_date, mod_uid, mod_date 
from tb_device_group
where 1=1

and site_id = #{siteId }

/* 장치그룹내 장치목록 조회 */
select 
	device_id, site_id, user_idx, device_name, device_grp_idx, device_type, inst_type, del_yn, reg_uid, reg_date, mod_uid, mod_date 
from tb_device
where 1=1 

and site_id =  #{siteId }


and device_grp_idx =  #{deviceGrpIdx }

/* 장치목록(사이트 전체 장치 중 특정 장치그룹 제외) 조회 */
select 
	device_id, site_id, user_idx, device_name, device_grp_idx, device_type, inst_type, del_yn, reg_uid, reg_date, mod_uid, mod_date 
from tb_device
where 1=1

and site_id =  #{siteId }
 

and device_grp_idx !=  #{deviceGrpIdx }

mapper.update:
/* 장치 수정 */ update tb_device set
device_name = #{deviceName },
device_grp_idx = #{deviceGrpIdx },
device_type = #{deviceType },
inst_type = #{instType },
mod_uid = #{modUid }, mod_date = now() where 1=1 and device_id = #{deviceId }
